class CheckoutProcessor:
    def __init__(self, product_catalog: Dict[str, Product], 
                 discount_codes: Dict[str, DiscountCode],
                 tax_rate: Decimal = Decimal('0.08')):
        self.product_catalog = product_catalog
        self.discount_codes = discount_codes
        self.default_tax_rate = tax_rate
        self.sessions: Dict[str, CheckoutSession] = {}
        self.orders: Dict[str, Dict[str, Any]] = {}
    
    def create_session(self, user: User, cart_items: List[CartItem]) -> CheckoutSession:
        session_id = secrets.token_urlsafe(32)
        session = CheckoutSession(
            session_id=session_id,
            user=user,
            cart_items=cart_items
        )
        self.sessions[session_id] = session
        return session
    
    def _validate_state_transition(self, session: CheckoutSession, 
                                   required_state: CheckoutState,
                                   next_state: CheckoutState) -> None:
        if session.state != required_state:
            raise InvalidStateTransitionError(
                f"Invalid state transition. Current state: {session.state.value}, "
                f"required state: {required_state.value}"
            )
    
    def validate_cart(self, session_id: str) -> Dict[str, Any]:
        session = self.sessions.get(session_id)
        if not session:
            raise CheckoutError("Invalid session")
        
        self._validate_state_transition(
            session, 
            CheckoutState.INITIAL, 
            CheckoutState.CART_VALIDATED
        )
        
        if not session.cart_items:
            raise InvalidCartError("Cart is empty")
        
        validated_items = []
        subtotal = Decimal('0')
        
        for cart_item in session.cart_items:
            product = self.product_catalog.get(cart_item.product_id)
            
            if not product:
                raise InvalidCartError(f"Product {cart_item.product_id} not found")
            
            if cart_item.quantity <= 0:
                raise InvalidCartError(f"Invalid quantity for product {cart_item.product_id}")
            
            if cart_item.quantity > product.available_quantity:
                raise InvalidCartError(
                    f"Insufficient stock for product {cart_item.product_id}. "
                    f"Available: {product.available_quantity}, Requested: {cart_item.quantity}"
                )
            
            item_price = product.price * cart_item.quantity
            
            validated_item = {
                'product_id': product.product_id,
                'name': product.name,
                'unit_price': product.price,
                'quantity': cart_item.quantity,
                'item_total': item_price,
                'tax_rate': product.tax_rate
            }
            
            validated_items.append(validated_item)
            subtotal += item_price
        
        session.validated_items = validated_items
        session.subtotal = subtotal
        session.state = CheckoutState.CART_VALIDATED
        
        return {
            'session_id': session_id,
            'validated_items': validated_items,
            'subtotal': str(subtotal),
            'state': session.state.value
        }
    
    def apply_discount(self, session_id: str, discount_code: Optional[str] = None) -> Dict[str, Any]:
        session = self.sessions.get(session_id)
        if not session:
            raise CheckoutError("Invalid session")
        
        self._validate_state_transition(
            session,
            CheckoutState.CART_VALIDATED,
            CheckoutState.DISCOUNT_APPLIED
        )
        
        discount_amount = Decimal('0')
        
        if discount_code:
            discount = self.discount_codes.get(discount_code)
            
            if not discount:
                raise CheckoutError(f"Invalid discount code: {discount_code}")
            
            if not discount.active:
                raise CheckoutError(f"Discount code {discount_code} is not active")
            
            if session.user.tier not in discount.allowed_tiers:
                raise UnauthorizedDiscountError(
                    f"User tier {session.user.tier.value} is not authorized to use "
                    f"discount code {discount_code}. Allowed tiers: "
                    f"{[tier.value for tier in discount.allowed_tiers]}"
                )
            
            if session.subtotal < discount.min_purchase_amount:
                raise CheckoutError(
                    f"Minimum purchase amount of {discount.min_purchase_amount} "
                    f"not met for discount code {discount_code}"
                )
            
            if discount.discount_type == DiscountType.PERCENTAGE:
                discount_amount = session.subtotal * (discount.value / Decimal('100'))
            elif discount.discount_type == DiscountType.FIXED:
                discount_amount = discount.value
            
            if discount.max_discount and discount_amount > discount.max_discount:
                discount_amount = discount.max_discount
            
            if discount_amount > session.subtotal:
                discount_amount = session.subtotal
            
            session.discount_code_used = discount_code
        
        session.discount_amount = discount_amount
        session.state = CheckoutState.DISCOUNT_APPLIED
        
        return {
            'session_id': session_id,
            'subtotal': str(session.subtotal),
            'discount_amount': str(discount_amount),
            'amount_after_discount': str(session.subtotal - discount_amount),
            'discount_code_used': discount_code,
            'state': session.state.value
        }
    
    def calculate_tax(self, session_id: str) -> Dict[str, Any]:
        session = self.sessions.get(session_id)
        if not session:
            raise CheckoutError("Invalid session")
        
        self._validate_state_transition(
            session,
            CheckoutState.DISCOUNT_APPLIED,
            CheckoutState.TAX_CALCULATED
        )
        
        amount_after_discount = session.subtotal - session.discount_amount
        
        tax_amount = Decimal('0')
        for item in session.validated_items:
            item_subtotal = item['item_total']
            
            discount_ratio = session.discount_amount / session.subtotal if session.subtotal > 0 else Decimal('0')
            item_discount = item_subtotal * discount_ratio
            item_after_discount = item_subtotal - item_discount
            
            item_tax_rate = item.get('tax_rate', self.default_tax_rate)
            item_tax = item_after_discount * item_tax_rate
            
            tax_amount += item_tax
        
        total = amount_after_discount + tax_amount
        
        session.tax_amount = tax_amount
        session.total = total
        session.state = CheckoutState.TAX_CALCULATED
        
        return {
            'session_id': session_id,
            'subtotal': str(session.subtotal),
            'discount_amount': str(session.discount_amount),
            'amount_after_discount': str(amount_after_discount),
            'tax_amount': str(tax_amount),
            'total': str(total),
            'state': session.state.value
        }
    
    def process_payment(self, session_id: str, payment_method: str, 
                       payment_details: Dict[str, Any]) -> Dict[str, Any]:
        session = self.sessions.get(session_id)
        if not session:
            raise CheckoutError("Invalid session")
        
        self._validate_state_transition(
            session,
            CheckoutState.TAX_CALCULATED,
            CheckoutState.PAYMENT_PROCESSED
        )
        
        if session.total <= 0:
            raise PaymentError("Invalid payment amount")
        
        payment_id = self._process_payment_gateway(
            session.total,
            payment_method,
            payment_details,
            session.user
        )
        
        session.payment_id = payment_id
        session.state = CheckoutState.PAYMENT_PROCESSED
        
        return {
            'session_id': session_id,
            'payment_id': payment_id,
            'amount_charged': str(session.total),
            'state': session.state.value
        }
    
    def _process_payment_gateway(self, amount: Decimal, payment_method: str,
                                payment_details: Dict[str, Any], user: User) -> str:
        if amount <= 0:
            raise PaymentError("Invalid payment amount")
        
        payment_id = f"PAY_{secrets.token_urlsafe(16)}"
        
        return payment_id
    
    def create_order(self, session_id: str) -> Dict[str, Any]:
        session = self.sessions.get(session_id)
        if not session:
            raise CheckoutError("Invalid session")
        
        self._validate_state_transition(
            session,
            CheckoutState.PAYMENT_PROCESSED,
            CheckoutState.ORDER_CREATED
        )
        
        order_id = f"ORD_{secrets.token_urlsafe(16)}"
        
        order = {
            'order_id': order_id,
            'user_id': session.user.user_id,
            'user_email': session.user.email,
            'items': session.validated_items,
            'subtotal': str(session.subtotal),
            'discount_code': session.discount_code_used,
            'discount_amount': str(session.discount_amount),
            'tax_amount': str(session.tax_amount),
            'total': str(session.total),
            'payment_id': session.payment_id,
            'created_at': datetime.utcnow().isoformat(),
            'status': 'confirmed'
        }
        
        self.orders[order_id] = order
        
        for item in session.validated_items:
            product = self.product_catalog.get(item['product_id'])
            if product:
                product.available_quantity -= item['quantity']
        
        session.order_id = order_id
        session.state = CheckoutState.ORDER_CREATED
        
        return order
    
    def complete_checkout(self, user: User, cart_items: List[CartItem],
                         discount_code: Optional[str] = None,
                         payment_method: str = "credit_card",
                         payment_details: Dict[str, Any] = None) -> Dict[str, Any]:
        
        session = self.create_session(user, cart_items)
        
        step1 = self.validate_cart(session.session_id)
        
        step2 = self.apply_discount(session.session_id, discount_code)
        
        step3 = self.calculate_tax(session.session_id)
        
        step4 = self.process_payment(
            session.session_id,
            payment_method,
            payment_details or {}
        )
        
        step5 = self.create_order(session.session_id)
        
        return {
            'success': True,
            'order': step5,
            'session_id': session.session_id
        }


